```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Convert records to the format expected by sqlgen's write function
  // Note: sqlgen's write function expects a container of objects, not tuples
  // We need to convert the vector of tuples to a vector of the appropriate struct type
  std::vector<std::remove_cvref_t<T>> converted_records;
  converted_records.reserve(records.size());

  for (const auto& record : records) {
    // Assuming T is one of the defined structs (Student, Course, etc.)
    // We need to create an instance of the struct and populate its fields
    // This requires knowing the field order and types of the struct T
    // Since we're using templates, we need to handle each struct type differently

    if constexpr (std::is_same_v<T, Student>) {
      Student student;
      std::tie(student.SNo, student.SName, student.Sex, student.Birthday, student.Major, student.Scorses, student.Remark) = record;
      converted_records.push_back(student);
    } else if constexpr (std::is_same_v<T, Course>) {
      Course course;
      std::tie(course.CID, course.CName, course.Term, course.CTime, course.Credit) = record;
      converted_records.push_back(course);
    } else if constexpr (std::is_same_v<T, Score>) {
      Score score;
      std::tie(score.ScID, score.SNo, score.CID, score.Score) = record;
      converted_records.push_back(score);
    } else if constexpr (std::is_same_v<T, Major>) {
      Major major;
      std::tie(major.MID, major.MName) = record;
      converted_records.push_back(major);
    } else {
      throw std::invalid_argument("Unsupported type for add_eas_records");
    }
  }

  // Use sqlgen's write function to insert the records
  auto write_result = sqlgen::write(conn, converted_records);
  if (!write_result) {
    throw std::runtime_error("Failed to write records to database");
  }
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Determine the primary key column name based on the table
  std::string primary_key_col;
  if (table_name == "Student") {
    primary_key_col = "SNo";
  } else if (table_name == "Course") {
    primary_key_col = "CID";
  } else if (table_name == "Score") {
    primary_key_col = "ScID";
  } else if (table_name == "Major") {
    primary_key_col = "MID";
  } else {
    throw std::invalid_argument("Invalid table name");
  }

  // Construct the DELETE statement using sqlgen's delete_from and where functionality
  auto delete_stmt = sqlgen::delete_from<std::remove_cvref_t<decltype(conn)::ConnType>>
                   | sqlgen::where("id"_c == record_id); // Using "id" as generic primary key name

  // Execute the delete operation
  auto result = delete_stmt(conn);
  if (!result) {
    throw std::runtime_error("Failed to delete record from database");
  }
}
```

**Note:** This implementation makes several assumptions:

1. The `record_id` parameter is expected to be in a format compatible with the primary key type of the respective table
2. The primary key column names are known and mapped based on the table name
3. The `delete_from` function works with a generic `"id"_c` column name, which may need adjustment based on actual primary key column names
