#pragma once

#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace schema_create_trigger_audit_log {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  double price;
  int stock;
};

struct AuditLog {
  sqlgen::PrimaryKey<int, sqlgen::auto_incr> log_id;
  std::string table_name;
  int record_id;
  std::string action;
  sqlgen::DateTime timestamp;
};

/**
 * Function: Create a trigger for auditing changes on Product table.
 * 
 * @return true if trigger creation succeeds, false otherwise
 */
bool create_trigger_audit_log() {
  // Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");

  // Check if connection was successful
  if (!conn_result) {
    return false;
  }

  auto conn = *conn_result;

  // Execute the SQL statement to create the trigger
  auto result = conn->execute(
    "CREATE TRIGGER IF NOT EXISTS audit_product_update\n"
    "AFTER UPDATE ON Product\n"
    "BEGIN\n"
    "    INSERT INTO AuditLog (table_name, record_id, action, timestamp)\n"
    "    VALUES ('Product', OLD.product_id, 'UPDATE', CURRENT_TIMESTAMP);\n"
    "END;"
  );

  // Return true if execution succeeded, false otherwise
  return result.is_ok();
}

}  // namespace schema_create_trigger_audit_log
```

