```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen::literals;

  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = *conn_result;

  // 2. Begin transaction
  auto transaction_result = sqlgen::begin_transaction(conn);
  if (!transaction_result) {
    return false;
  }
  auto transaction = *transaction_result;

  try {
    // 3. Read from_account balance
    auto from_account_result = (sqlgen::read<Account> | sqlgen::where("account_id"_c == from_account_id))(transaction);
    if (!from_account_result) {
      transaction->rollback();
      return false;
    }
    auto from_account = *from_account_result;

    // 4. Check if from_account has sufficient balance
    if (from_account.balance < amount) {
      transaction->rollback();
      return false;
    }

    // 5. Update from_account: balance = balance - amount
    auto update_from_result = (sqlgen::update<Account>("balance"_c.set("balance"_c - amount)) 
                             | sqlgen::where("account_id"_c == from_account_id))(transaction);
    if (!update_from_result) {
      transaction->rollback();
      return false;
    }

    // 6. Update to_account: balance = balance + amount
    auto update_to_result = (sqlgen::update<Account>("balance"_c.set("balance"_c + amount)) 
                           | sqlgen::where("account_id"_c == to_account_id))(transaction);
    if (!update_to_result) {
      transaction->rollback();
      return false;
    }

    // 7. Commit transaction if all operations succeed
    auto commit_result = transaction->commit();
    if (!commit_result) {
      transaction->rollback();
      return false;
    }

    return true;

  } catch (...) {
    // 8. Rollback if any operation fails
    transaction->rollback();
    return false;
  }
}

}  // namespace transaction_transfer_funds
```

